        /// <summary>
        /// Disposes resources if they were created by us.
        /// </summary>
        public void Dispose()
        {
            var s = _state;
            if (s is not null)
            {
                // CreateAsync / ApplyConfigurationAsync path: all resources are in ApiState.
                // RefCounter is not released here because Dispose() means the caller is done
                // with the whole instance — we dispose immediately.
                s.Dispose();
                return;
            }
            // Legacy constructor path: dispose the backing ApiClient directly.
            _apiClientBacking?.Dispose();
        }

